base:
.section {
	padding: 6px;
	border-radius: var(--radius-l);
	background-color: var(--bg-2);
}

.tree {
	display: grid;
	grid-template-rows: auto minmax(0, 1fr);
	grid-template-columns: minmax(0, 1fr);
	gap: 12px;

	&:focus {
		/* The focus state is displayed on the item row instead. */
		outline: none;
	}
}

.changesContainer {
	padding-inline: var(--panel-padding);
}

.headInfoScroller {
	padding-inline: var(--panel-padding);
	padding-bottom: var(--panel-padding);
	scroll-padding: var(--panel-padding);
}

.headInfo {
	display: flex;
	row-gap: 12px;
	flex-direction: column;
}

.segments {
	display: flex;
	/* The size of an item row. Eventually this should be a fixed/shared value,
	somehow. */
	row-gap: 10px;
	flex-direction: column;
}

.segment {
	display: flex;
	flex-direction: column;
}

.stack {
	display: flex;
	flex-direction: column;
	padding-bottom: 0;
}

.editorForm {
	display: flex;
	row-gap: 6px;
	flex-grow: 1;
	flex-direction: column;
	min-width: 0;
	padding-block: 6px 8px;
	padding-right: 4px;
}

.editorInput {
	flex-grow: 1;

	&:focus {
		outline: none;
	}
}

.editorHelp {
	display: flex;
	margin-left: -6px;
	font-size: 11px;
	line-height: 1.3;

	& > button {
		text-transform: lowercase;
	}
}

.editorShortcut {
	color: var(--fill-gray-fg);
}

.editorShortcutLabel {
	color: var(--fill-gray-fg);
	opacity: 0.6;
