	display: flex;
	row-gap: 2px;
	flex-direction: column;
}

.changesCountBubble {
	display: inline-flex;
	align-items: center;
	justify-content: center;
	min-width: 20px;
	height: 16px;
	margin-inline-start: 6px;
	margin-block-start: -2px;
	padding-inline: 4px;
	padding-block: 2px;
	border-radius: 10px;
	background: var(--fill-gray-bg);
	color: var(--fill-gray-fg);
	font-size: 10px;
	vertical-align: middle;

	.selected & {
		background: var(--fill-gray-fg);
		color: var(--fill-gray-bg);
	}
}

.commitControls {
	display: flex;
	row-gap: 2px;
	flex-direction: column;
}

.commitTextarea {
	resize: none;
	field-sizing: content;
	box-sizing: content-box;
	min-height: calc(2lh);
	max-height: calc(10lh);
	padding-inline: 8px;
	padding-block: 6px;

	&:focus {
		outline: none;
	}
}

.commitControlsFooter {
	display: flex;
	column-gap: 2px;
}

.commitDropdownButton {
	display: flex;

	& > * {
		overflow: hidden;
		background: var(--bg-1);
	}

	& > :first-child {
		border-right: 0;
		border-start-end-radius: 0;
		border-end-end-radius: 0;
	}

	& > :last-child {
		border-left: 1px solid color-mix(in srgb, var(--fill-gray-bg) 30%, transparent);
		border-start-start-radius: 0;
		border-end-start-radius: 0;
	}
}

.commitTargetComboboxTrigger {
	/* Override button inline-flex to fix overflow behaviour. */
	display: block;
	flex-grow: 1;
	overflow: hidden;
	background: var(--bg-1);
	text-overflow: ellipsis;
	white-space: nowrap;
}

.commitTargetComboboxPopup {
	display: flex;
	flex-direction: column;
	width: max(var(--anchor-width), 200px);
}

.commitTargetComboboxInput {
	padding-inline: 10px;
	padding-block: 4px;
	border-bottom: 1px solid var(--border-2);

	&:focus {
		outline: none;
	}
}

.commitTargetComboboxList {
	--approx-input-height: 50px;
	max-height: min(300px, calc(var(--available-height) - var(--approx-input-height)));
	overflow: auto;

	&:not(:empty) {
		padding-block: 4px;
	}
}

.commitTargetComboboxItem {
	padding-inline: 10px;
	padding-block: 4px;
	overflow: hidden;
	text-overflow: ellipsis;
	white-space: nowrap;
	cursor: default;

	&[data-highlighted] {
		background-color: var(--bg-2);
	}
}

.commitTargetComboboxEmpty {
	padding-inline: 10px;
	padding-block: 4px;
	color: var(--color-text-secondary);
}

[data-status="LocalOnly"] {
	--commit-status-color: var(--commit-local);
}

[data-status="LocalAndRemote"] {
	--commit-status-color: var(--commit-remote);
}

[data-status="Integrated"] {
	--commit-status-color: var(--commit-integrated);
}

[data-status="Diverged"] {
	--commit-status-color: var(--commit-local);
}

.commitState {
	display: grid;
	justify-content: center;
	inline-size: 14px;
	margin-block-start: 3px;
}

.commitStateIcon {
	aspect-ratio: 1;
	inline-size: 10px;
	block-size: 10px;
	border: 1.5px solid var(--commit-status-color);
	border-radius: 50%;
}

.commitCheckbox {
	margin-block-start: 1px;
	opacity: 0;

	.treeWithCheckedCommits &,
	.itemRow:hover &,
	&:focus {
		opacity: 1;
