	.tree:not(.treeWithDefaultOutlineMode):not(.treeWithCheckedCommits) & {
		display: none;
	}
}

.commitStateWithCheckbox {
	display: grid;
	justify-items: center;

	& > * {
		grid-area: 1 / 1;
	}
}

