                description: format!(
                    "Expected to see {:?}, but got {:?}",
                    expected_service_announcement,
                    announced_service.trim()
                ),
            }));
        }

        let capabilities::recv::Outcome {
            capabilities,
            refs,
            protocol: actual_protocol,
        } = Capabilities::from_lines_with_version_detection(line_reader)?;
