    ///
    /// It can be configured further before starting the actual walk.
    pub fn rev_walk(
        &self,
        tips: impl IntoIterator<Item = impl Into<git_hash::ObjectId>>,
    ) -> revision::walk::Platform<'_> {
        revision::walk::Platform::new(tips, self)
    }
}

